var _embeddings = faqEmbeddings_default;
function loadEmbeddings() {
  return _embeddings;
}
function cosineSimilarity(a, b) {
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}
function keywordSearch(query, topK) {
  const q = query.toLowerCase();
  const scored = knowledgeChunks.map((c) => ({
    chunk: c,
    hits: c.keywords.filter((k) => q.includes(k.toLowerCase()) || k.toLowerCase().includes(q)).length
  }));
  return scored.filter((s) => s.hits > 0).sort((a, b) => b.hits - a.hits).slice(0, topK).map((s) => s.chunk);
}
async function searchKnowledge(query, queryVector, topK = 3, threshold = 0.45) {
  const embeddings = loadEmbeddings();
  const vectorResults = [];
  if (embeddings.length > 0) {
    const scored = embeddings.map(({ id, vector }) => ({
      id,
      score: cosineSimilarity(queryVector, vector)
    }));
    const top = scored.filter((s) => s.score >= threshold).sort((a, b) => b.score - a.score).slice(0, topK);
    for (const { id, score } of top) {
      const chunk = knowledgeChunks.find((c) => c.id === id);
      if (chunk) vectorResults.push({ ...chunk, score });
    }
  }
  const seen = new Set(vectorResults.map((c) => c.id));
  const kwResults = keywordSearch(query, topK).filter((c) => !seen.has(c.id)).map((c) => ({ ...c, score: 0 }));
  return [...vectorResults, ...kwResults].slice(0, topK);
}

