async function generateAnswer(systemPrompt, history, userMessage, maxTokens = 500) {
  const contents = [
    ...history.map((h) => ({
      role: h.role === "assistant" ? "model" : "user",
      parts: [{ text: h.content }]
    })),
    { role: "user", parts: [{ text: userMessage }] }
  ];
  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${ENV.geminiApiKey}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        system_instruction: { parts: [{ text: systemPrompt }] },
        contents,
        generationConfig: { maxOutputTokens: maxTokens }
      })
    }
  );
  if (!res.ok) {
    const err = await res.text();
    console.error("[chatbot] generateContent error:", res.status, err);
    throw new Error(`Gemini generateContent failed: ${res.status} \u2013 ${err}`);
  }
  const data = await res.json();
  return data.candidates[0]?.content.parts[0]?.text ?? "\u62B1\u6B49\uFF0C\u6211\u73FE\u5728\u7121\u6CD5\u56DE\u7B54\uFF0C\u8ACB\u7A0D\u5F8C\u518D\u8A66\u3002";
}
async function embedQuery(text2) {
  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key=${ENV.geminiApiKey}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "models/gemini-embedding-001",
        content: { parts: [{ text: text2 }] }
      })
    }
  );
  if (!res.ok) throw new Error(`Gemini embed failed: ${res.status}`);
  const data = await res.json();
  return data.embedding.values;
}
var chatbotRouter = router({
  chat: publicProcedure.input(
    z3.object({
      message: z3.string().min(1).max(500),
      history: z3.array(
        z3.object({
          role: z3.enum(["user", "assistant"]),
          content: z3.string()
        })
      ).max(10).default([])
    })
  ).mutation(async ({ input }) => {
    const lastTurn = input.history.slice(-2).map((h) => h.content).join(" ");
    const queryText = lastTurn ? `${lastTurn} ${input.message}` : input.message;
    let queryVector;
    try {
      queryVector = await embedQuery(queryText);
    } catch (e) {
      console.error("[chatbot] embed error:", e);
      throw new TRPCError4({ code: "INTERNAL_SERVER_ERROR", message: `Embed failed: ${e instanceof Error ? e.message : String(e)}` });
    }
    const relevantChunks = await searchKnowledge(queryText, queryVector, 3, 0.45);
    const topChunk = relevantChunks[0];
    const isProductQuery = topChunk?.category === "\u5546\u54C1\u63A8\u85A6" && topChunk.score >= 0.72 && (topChunk.relatedProductIds?.length ?? 0) > 0;
    const relatedProducts = isProductQuery ? (topChunk.relatedProductIds ?? []).map((id) => products.find((p) => p.id === id)).filter((p) => !!p) : [];
    let ragContext = "";
    if (relevantChunks.length > 0) {
      ragContext = "\n\n\u3010\u76F8\u95DC\u5E38\u898B\u554F\u984C\u3011\n" + relevantChunks.map((c) => `Q: ${c.question}
A: ${c.answer}`).join("\n\n");
    }
    if (relatedProducts.length > 0) {
      ragContext += "\n\n\u3010\u53EF\u63A8\u85A6\u7684\u76F8\u95DC\u5546\u54C1\u3011\n" + relatedProducts.map((p) => `- ${p.name}\uFF08NT$${p.price}\uFF09\uFF1A${p.subtitle} \u5546\u54C1\u9023\u7D50\uFF1A/products/${p.id}`).join("\n");
    }
    const hasGoodMatch = relevantChunks.some((c) => c.score >= 0.5);
    if (!hasGoodMatch) {
      ragContext += "\n\n\u3010\u5099\u63F4\u8CC7\u8A0A\u3011\n\u82E5\u9867\u5BA2\u7684\u9700\u6C42\u5728\u73FE\u6709\u5546\u54C1\u4E2D\u627E\u4E0D\u5230\u5B8C\u5168\u7B26\u5408\u7684\u6B3E\u5F0F\uFF0C\u53EF\u63A8\u85A6\u300C\u5BA2\u88FD\u5316\u6C34\u6676\u624B\u934A\u300D\u670D\u52D9\u3002\u8001\u95C6\u6703\u6839\u64DA\u9867\u5BA2\u7684\u529F\u6548\u9700\u6C42\uFF08\u5982\u62DB\u6843\u82B1\u3001\u6539\u5584\u5065\u5EB7\u3001\u5316\u89E3\u5C0F\u4EBA\u3001\u63D0\u5347\u67D0\u7A2E\u7279\u5B9A\u904B\u52E2\u7B49\uFF09\u91CF\u8EAB\u8A2D\u8A08\u5C08\u5C6C\u624B\u934A\u3002\u5BA2\u88FD\u5316\u65B9\u6848\u9801\u9762\uFF1Ahttps://goodaytarot.com/custom\n\u4E5F\u6B61\u8FCE\u900F\u904E LINE \u8A62\u554F\uFF1Ahttps://line.me/R/ti/p/@011tymeh";
    }
    const reply = await generateAnswer(
      SYSTEM_PROMPT + ragContext,
      input.history.slice(-10),
      input.message,
      1024
    );
    return {
      reply,
      relatedProducts: relatedProducts.map((p) => ({
        id: p.id,
        name: p.name,
        price: p.price,
        image: p.image,
        href: `/products/${p.id}`
      })),
      retrievedChunks: relevantChunks.map((c) => c.question)
    };
  })
});

// server/routers/inventory.ts
import { z as z4 } from "zod";
var inventoryRouter = router({
  /**
   * 查詢商品可購買狀態（公開）
   */
  getAvailability: publicProcedure.input(z4.object({ productId: z4.string() })).query(async ({ input }) => {
    return getProductAvailability(input.productId);
  }),
  /**
   * 批次查詢多個商品的庫存狀態
   */
  getBatchAvailability: publicProcedure.input(z4.object({ productIds: z4.array(z4.string()) })).query(async ({ input }) => {
    const results = await Promise.all(
      input.productIds.map(async (id) => ({
        productId: id,
        ...await getProductAvailability(id)
      }))
    );
    return results;
  }),
  /**
   * 嘗試鎖定庫存（進入結帳時呼叫，保留 10 分鐘）
   */
  acquireLock: publicProcedure.input(
    z4.object({
      items: z4.array(
        z4.object({
          productId: z4.string(),
          quantity: z4.number().min(1)
        })
      ),
      sessionToken: z4.string()
    })
  ).mutation(async ({ input }) => {
    const results = [];
    for (const item of input.items) {
      const result = await acquireInventoryLock(
        item.productId,
        item.quantity,
        input.sessionToken
      );
      results.push({ productId: item.productId, ...result });
      if (!result.success) {
        await releaseSessionLocks(input.sessionToken);
        return { success: false, failedItem: item.productId, reason: result.reason };
      }
    }
    return { success: true };
  }),
  /**
   * 釋放庫存鎖定（取消結帳時呼叫）
   */
  releaseLock: publicProcedure.input(z4.object({ sessionToken: z4.string() })).mutation(async ({ input }) => {
    await releaseSessionLocks(input.sessionToken);
    return { success: true };
  }),
  /**
   * 管理員設定商品庫存
   */
  setInventory: adminProcedure.input(
    z4.object({
      productId: z4.string(),
      productName: z4.string(),
      stock: z4.number().min(-1),
      // -1 = 無限庫存
      allowPreorder: z4.boolean().optional().default(false),
      preorderNote: z4.string().optional()
    })
  ).mutation(async ({ input }) => {
    await upsertProductInventory({
      productId: input.productId,
      productName: input.productName,
      stock: input.stock,
      allowPreorder: input.allowPreorder,
      preorderNote: input.preorderNote
    });
    return { success: true };
  }),
  /**
   * 管理員取得商品庫存設定
   */
  getInventory: adminProcedure.input(z4.object({ productId: z4.string() })).query(async ({ input }) => {
    return getProductInventory(input.productId);
  })
});

